VALUES('DEVX-27', 'Reports check in error “Server refused to render file.”', 'When attempting to check in reports from the repository, we encountered the error message “Server refused to render file.” This issue has been consistently occurring and is significantly impacting our daily operations. Resolving this issue is a high priority for us.', NULL, 'To Do', 'Medium', 'Bug', 'Nuwan Hemantha', 'Portia Waduarachchi', '{}', '{}', '2026-03-26 16:54:17.322', NULL, '2026-03-26 17:06:17.483', '[{"id": "10025", "body": "There is a file size limitation for uploading files in the check-in option. -This is a known issue. Currently, the check-in feature supports - Maximum File Size is 20MB", "author": "Portia Waduarachchi", "created": "2026-03-26T16:57:59.993+0530", "updated": "2026-03-26T16:57:59.993+0530"}, {"id": "10026", "body": "After release 3.6.2 on Jan 13, 2026, the check-in feature currently supports a Maximum File Size is 50MB", "author": "Portia Waduarachchi", "created": "2026-03-26T17:01:52.698+0530", "updated": "2026-03-26T17:01:52.698+0530"}]'::jsonb, '{"id": "10026", "key": "DEVX-27", "self": "https://api.atlassian.com/ex/jira/6a02dde6-47b8-4c00-a42c-3bd078e9c043/rest/api/3/issue/10026", "expand": "renderedFields,names,schema,operations,editmeta,changelog,versionedRepresentations", "fields": {"labels": [], "status": {"id": "10000", "name": "To Do", "self": "https://api.atlassian.com/ex/jira/6a02dde6-47b8-4c00-a42c-3bd078e9c043/rest/api/3/status/10000", "iconUrl": "https://nwnhemantha.atlassian.net/images/icons/statuses/generic.png", "description": "", "statusCategory": {"id": 2, "key": "new", "name": "To Do", "self": "https://api.atlassian.com/ex/jira/6a02dde6-47b8-4c00-a42c-3bd078e9c043/rest/api/3/statuscategory/2", "colorName": "blue-gray"}}, "comment": {"self": "https://api.atlassian.com/ex/jira/6a02dde6-47b8-4c00-a42c-3bd078e9c043/rest/api/3/issue/10026/comment", "total": 2, "startAt": 0, "comments": [{"id": "10025", "body": {"type": "doc", "content": [{"typ