"https://secure.gravatar.com/avatar/5a0fc7c165252fc8a1beed35a2c82de2?d=https%3A%2F%2Favatar-management--avatars.us-west-2.prod.public.atl-paas.net%2Finitials%2FPW-4.png"}, "accountType": "atlassian", "displayName": "Portia Waduarachchi", "emailAddress": "portia.waduarachchi@otelier.io"}, "issuetype": {"id": "10007", "name": "Bug", "self": "https://api.atlassian.com/ex/jira/6a02dde6-47b8-4c00-a42c-3bd078e9c043/rest/api/3/issuetype/10007", "iconUrl": "https://api.atlassian.com/ex/jira/6a02dde6-47b8-4c00-a42c-3bd078e9c043/rest/api/2/universal_avatar/view/type/issuetype/avatar/10303?size=medium", "subtask": false, "avatarId": 10303, "entityId": "2e3ac022-0ebb-4f0a-aa86-1b8557ee36dd", "description": "Bugs track problems or errors.", "hierarchyLevel": 0}, "components": [], "resolution": null, "description": {"type": "doc", "content": [{"type": "paragraph", "content": [{"text": "For ", "type": "text"}, {"text": "Test hotel 1", "type": "text", "marks": [{"type": "strong"}]}, {"text": " looks like the signature pack is not triggering automatically.", "type": "text"}]}, {"type": "paragraph", "content": [{"text": "We noticed this for 1/18 signature pack and when we trigger the pack (Signature mandatory style), we are receiving the following AOC", "type": "text"}]}, {"type": "paragraph", "content": [{"text": "“\"Level: \":\"WARN\",\"Application: \":\"SIGNATURE-TRIGGER\",\"Environment: \":\"prod\",\"Message: \":\"TRIGGER_CANCELLED\",\"Reason: \":\"Trigger cancel due to missing reports\",\"Group: \":\"ABC Hospitality\",\"Hotel: \":\"Test Hotel 1\",\"Business Date: \":\"2026-01-18\",\"Type: \":\"MANUAL\",\"Scheduled As: \":\"MANDATORY\",\"Back days: \":0,\"By: \"", "type": "text", "marks": [{"type": "strong"}]}, {"text": ":", "type": "text", "marks": [{"type": "link", "attrs": {"href": "mailto::\"thanuja.perera@otelier.io"}}, {"type": "strong"}, {"type": "underline"}]}, {"text": "testuser@gmail.com", "type": "text", "marks": [{"type": "strong"}, {"type": "underline"}]}, {"text": "\",\"LogId: \":\"aaabbb111-2345-6789-0123-ccc741eee852\",\"Following report are missing or not in PDF format: \":\"Report 1\"“", "type": "text", "marks": [{"type": "strong"}]}]}, {"type": "paragraph", "content": [{"text": " ", "type": "text"}]}, {"type": "paragraph", "content": [{"text": "But the “", "type": "text"}, {"text": "Report 1", "type": "text", "marks": [{"type": "strong"}]}, {"text": "“ report is not a signature required report anymore.", "type": "text"}]}, {"type": "paragraph", "content": [{"text": "In Marriott SM, this report is listed as a ", "type": "text"}, {"text": "signature-required", "type": "text", "marks": [{"type": "strong"}]}, {"text": " report and also has a ", "type": "text"}, {"text": "signature deactivation date", "type": "text", "marks": [{"type": "strong"}]}, {"text": ".", "type": "text"}]}, {"type": "paragraph", "content": [{"text": "We configured the report this way because the client requested that the report appear as a ", "type": "text"}, {"text": "non-signature", "type": "text", "marks": [{"type": "strong"}]}, {"text": " report starting from ", "type": "text"}, {"text": "2025-01-29", "type": "text", "marks": [{"type": "strong"}]}, {"text": ". When the report was originally created, it was first set up as a ", "type": "text"}, {"text": "signature-required", "type": "text", "marks": [{"type": "strong"}]}, {"text": " report.", "type": "text"}]}, {"type": "paragraph", "content": [{"text": "Normally, to make a report non-signature starting from a specific date, we ", "type": "text"}, {"text": "disable the signature-mandatory toggle", "type": "text", "marks": [{"type": "strong"}]}, {"text": " and ", "type": "text"}, {"text": "add a signature deactivation date", "type": "text", "marks": [{"type": "strong"}]}, {"text": ". This ensures that the report is treated as a ", "type": "text"}, {"text": "non-signature report from the specified deactivation date onward", "type": "text", "marks": [{"type": "strong"}]}, {"text": ".", "type": "text"}]}