VALUES('DEVX-21', 'Showing error message: "Incorrect configuration" in Compliance.', 'Showing error message: "Incorrect configuration" in Compliance.When we add reports from the template to SM, the reports are saved on the SM side but are not added to the QC DB. As a result, the error message "Incorrect configuration" appears in Compliance', NULL, 'To Do', 'Medium', 'Bug', 'Portia Waduarachchi', 'Portia Waduarachchi', '{}', '{}', '2026-03-26 14:03:29.940', NULL, '2026-03-26 15:06:31.131', '[{"id": "10012", "body": "A hotel that does not have reports in compliance does not have the QC hotel ID in the hotel details. Seems like myAdmin backend is receiving an error from the QC database. Check if the QC DB connection and QC hotel ID", "author": "Portia Waduarachchi", "created": "2026-03-26T14:16:06.147+0530", "updated": "2026-03-26T14:32:38.640+0530"}]'::jsonb, '{"id": "10020", "key": "DEVX-21", "self": "https://api.atlassian.com/ex/jira/6a02dde6-47b8-4c00-a42c-3bd078e9c043/rest/api/3/issue/10020", "expand": "renderedFields,names,schema,operations,editmeta,changelog,versionedRepresentations", "fields": {"labels": [], "status": {"id": "10000", "name": "To Do", "self": "https://api.atlassian.com/ex/jira/6a02dde6-47b8-4c00-a42c-3bd078e9c043/rest/api/3/status/10000", "iconUrl": "https://nwnhemantha.atlassian.net/images/icons/statuses/generic.png", "description": "", "statusCategory": {"id": 2, "key": "new", "name": "To Do", "self": "https://api.atlassian.com/ex/jira/6a02dde6-47b8-4c00-a42c-3bd078e9c043/rest/api/3/statuscategory/2", "colorName": "blue-gray"}}, "comment": {"self": "https://api.atlassian.com/ex/jira/6a02dde6-47b8-4c00-a42c-3bd078e9c043/rest/api/3/issue/10020/comment", "total": 1, "startAt": 0, "comments": [{"id": "10012", "body": {"type": "doc", "content": [{"type": "paragraph", "content": [{"text": "A hotel that does not have reports in compliance does not have the QC hotel ID in the hotel details. Seems like myAdmin backend is receiving an error from the QC 