VALUES('DEVX-16', 'Signature Packs are not automatically triggering for multiple Marriott properties.', 'After the following Marriott properties submit the required signature report for DigiAudit, the signature packs are not triggering, but showing as an error message.ABC HMG - Demo hotel 1 - DH1EFG HMG - Test Hotel 1 - TH1', 'Done', 'Done', 'Medium', 'Bug', 'Nuwan Hemantha', 'Portia Waduarachchi', '{}', '{}', '2026-03-26 11:31:42.743', '2026-03-26 11:55:50.919', '2026-03-26 12:34:11.490', '[{"id": "10004", "body": "Enable Triggers should be true in the Hotel Configuration - DigiAudit section.", "author": "Portia Waduarachchi", "created": "2026-03-26T11:36:58.982+0530", "updated": "2026-03-26T11:36:58.982+0530"}, {"id": "10005", "body": "Signature Style empty on the SM hotel configuration. The required signature style has not been defined for this hotel. Need to correct the configuration accordingly and re-initiate the trigger.", "author": "Portia Waduarachchi", "created": "2026-03-26T11:37:11.968+0530", "updated": "2026-03-26T11:37:53.674+0530"}]'::jsonb, '{"id": "10015", "key": "DEVX-16", "self": "https://api.atlassian.com/ex/jira/6a02dde6-47b8-4c00-a42c-3bd078e9c043/rest/api/3/issue/10015", "expand": "renderedFields,names,schema,operations,editmeta,changelog,versionedRepresentations", "fields": {"labels": [], "status": {"id": "10003", "name": "Done", "self": "https://api.atlassian.com/ex/jira/6a02dde6-47b8-4c00-a42c-3bd078e9c043/rest/api/3/status/10003", "iconUrl": "https://nwnhemantha.atlassian.net/images/icons/statuses/generic.png", "description": "", "statusCategory": {"id": 3, "key": "done", "name": "Done", "self": "https://api.atlassian.com/ex/jira/6a02dde6-47b8-4c00-a42c-3bd078e9c043/rest/api/3/statuscategory/3", "colorName": "green"}}, "comment": {"self": "https://api.atlassian.com/ex/jira/6a02dde6-47b8-4c00-a42c-3bd078e9c043/rest/api/3/issue/10015/comment", "total": 2, "startAt": 0, "comments": [{"id": "10004", "body": {"type": "doc", "content": [{"type":